-- الدفعة الثالثة والأخيرة من ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft')
-- تحت "العقيدة والتوحيد" (aqeedah-tawheed) — تُكمِل استنفاد العنقود بالكامل
-- (11 تصنيفاً متبقياً بعد دفعتَي usul-fiqh/mustalah-hadith وaqeedah_batch1).
-- كل تصنيف يحصل على درس واحد حقيقي (lessons + lesson_sections +
-- lesson_citations)، مبني على مصادر عقدية معتمدة عند أهل السنة والجماعة
-- (العقيدة الواسطية وشرحها، العقيدة الطحاوية وشرحها، كتب مؤلَّفة معتمدة)،
-- مع استشهاد قرآني محلي محقَّق حرفياً من public/data/quran لكل درس.
-- التصنيفات الحساسة (firaq-madhahib، adyan-muasira، radd-shubuhat-aqeedah،
-- ilhad-shubuhat-fikriyya) عُرضت عرضاً موضوعياً موثَّقاً بلا تكفير عام أو
-- تعميم، التزاماً بتحذير الحساسية الموثَّق في CONTINUATION_PLAN.md.
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الأحد عشر عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) الصحابة وآل البيت
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='dd473678-f65e-4c7e-8801-ad5b765a00aa' AND title='عقيدة أهل السنة في الصحابة وآل البيت') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('عقيدة أهل السنة في الصحابة وآل البيت', 'محبة جميع صحابة النبي ﷺ وترتيب فضلهم، وتوقير أهل بيته دون غلو', 'dd473678-f65e-4c7e-8801-ad5b765a00aa', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'منزلة الصحابة', 'أهل السنة والجماعة يحبون أصحاب رسول الله ﷺ جميعاً، ولا يذكرون أحداً منهم إلا بخير، ويعتقدون أفضليتهم على من بعدهم بحسب سابقتهم وجهادهم، فأفضلهم الخلفاء الراشدون الأربعة على ترتيب خلافتهم: أبو بكر ثم عمر ثم عثمان ثم علي رضي الله عنهم، ثم بقية العشرة المبشرين بالجنة، ثم سائر الصحابة. وما جرى بينهم من خلاف فهو موضع اجتهاد يُلتمَس له العذر، لا يُتَّخذ سبباً للطعن فيهم أو التعصب لفريق ضد آخر.', 1),
    (v_lesson, 'evidence', 'أهل البيت ودليل الفريقين', 'يوقِّر أهل السنة أهل بيت النبي ﷺ ويحبونهم لقرابتهم منه ولفضلهم، من غير غلو يصل إلى ما يخالف التوحيد. قال تعالى في أزواجه وأهل بيته: ﴿إِنَّمَا يُرِيدُ اللَّهُ لِيُذْهِبَ عَنْكُمُ الرِّجْسَ أَهْلَ الْبَيْتِ وَيُطَهِّرَكُمْ تَطْهِيرًا﴾ (الأحزاب: 33)، وأثنى على السابقين من المهاجرين والأنصار بقوله: ﴿وَالسَّابِقُونَ الْأَوَّلُونَ مِنَ الْمُهَاجِرِينَ وَالْأَنْصَارِ وَالَّذِينَ اتَّبَعُوهُمْ بِإِحْسَانٍ رَضِيَ اللَّهُ عَنْهُمْ وَرَضُوا عَنْهُ﴾ (التوبة: 100).', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'العقيدة الواسطية — شيخ الإسلام ابن تيمية (فصل عقيدة أهل السنة في الصحابة)', 1);
  END IF;

  -- 2) الفتن وأشراط الساعة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='4fa58dd2-afaf-4067-8f42-e3a3ac72cc15' AND title='مدخل إلى أشراط الساعة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('مدخل إلى أشراط الساعة', 'التعريف بأشراط الساعة الصغرى والكبرى ووجوب الإيمان بها إجمالاً', '4fa58dd2-afaf-4067-8f42-e3a3ac72cc15', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وأقسامها', 'أشراط الساعة هي العلامات التي تسبق قيام الساعة وتدل على قربها، وتنقسم إلى صغرى وهي علامات كثيرة متقدمة تقع تباعاً (ككثرة الفتن وضياع الأمانة وتطاول الناس في البنيان)، وكبرى وهي عشر علامات عظيمة متلاحقة تقع قرب قيام الساعة مباشرة (كخروج الدجال ونزول عيسى عليه السلام ويأجوج ومأجوج وطلوع الشمس من مغربها)، كما جاء في حديث حذيفة بن أسيد الغفاري رضي الله عنه عند مسلم.', 1),
    (v_lesson, 'evidence', 'دليلها ووجوب الإيمان بها', 'ذكر القرآن الكريم مجيء أشراط الساعة صراحة، قال تعالى: ﴿فَهَلْ يَنْظُرُونَ إِلَّا السَّاعَةَ أَنْ تَأْتِيَهُمْ بَغْتَةً فَقَدْ جَاءَ أَشْرَاطُهَا﴾ (محمد: 18). ويجب الإيمان بما صح من هذه العلامات إجمالاً وتفصيلاً بحسب ثبوته، دون تحديد موعد قيام الساعة نفسها الذي استأثر الله بعلمه، ودون الانشغال بها عما ينفع المسلم من العمل الصالح.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أشراط الساعة — الشيخ يوسف بن عبدالله الوابل', 1);
  END IF;

  -- 3) مسائل الأسماء والأحكام
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='c7853add-2106-462b-b5a7-46eeec9c63ed' AND title='الإيمان وحكم مرتكب الكبيرة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الإيمان وحكم مرتكب الكبيرة', 'منزلة الإيمان بين الخوارج والمرجئة، وحكم أهل القبلة عند أهل السنة', 'c7853add-2106-462b-b5a7-46eeec9c63ed', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'حقيقة الإيمان عند أهل السنة', 'مذهب أهل السنة والجماعة أن الإيمان قول باللسان، واعتقاد بالجنان، وعمل بالأركان، يزيد بالطاعة وينقص بالمعصية. وهذا يوسّط بين قول الخوارج والمعتزلة الذين يُخرجون مرتكب الكبيرة من الإسلام بالكلية أو يجعلونه في منزلة بين المنزلتين، وقول المرجئة الذين يقولون إن المعصية لا تضر مع الإيمان.', 1),
    (v_lesson, 'evidence', 'حكم مرتكب الكبيرة', 'مرتكب الكبيرة من أهل القبلة لا يُحكَم بكفره ما لم يستحل ما حرَّم الله، بل يبقى تحت مشيئة الله إن مات قبل التوبة: إن شاء غفر له وإن شاء عذَّبه بقدر ذنبه ثم مصيره إلى الجنة، كما جاء في العقيدة الطحاوية: «ولا نكفر أحداً من أهل القبلة بذنب ما لم يستحله». وهذا الضبط يمنع الغلو في التكفير كما يمنع التساهل في شأن المعاصي.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'شرح العقيدة الطحاوية — ابن أبي العز الحنفي', 1);
  END IF;

  -- 4) الرد على الشبهات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='d1cccd5f-72c3-48cf-ad4f-021e15d224a1' AND title='منهج التعامل مع الشبهات العقدية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('منهج التعامل مع الشبهات العقدية', 'أصول منهجية للرد على الشبهات المثارة حول العقيدة بالحكمة والدليل', 'd1cccd5f-72c3-48cf-ad4f-021e15d224a1', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'أصل الشبهة وعلاجها', 'الشبهة أمر يلتبس فيه الحق بالباطل فيتوهم صاحبه أنه على صواب، وعلاجها يكون بردها إلى المحكم من نصوص الوحي والعقل الصحيح، وبيان وجه الخطأ فيها بدليل واضح لا بالتشويش أو رفع الصوت. وقد كان النبي ﷺ وأصحابه يواجهون شبهات المشركين وأهل الكتاب بالحجة الهادئة المفحمة، لا بالتجاهل ولا بالانفعال.', 1),
    (v_lesson, 'evidence', 'منهج الدعوة والمجادلة', 'أرشد الله تعالى إلى المنهج الأمثل في دعوة المخالف والرد عليه بقوله: ﴿ادْعُ إِلَى سَبِيلِ رَبِّكَ بِالْحِكْمَةِ وَالْمَوْعِظَةِ الْحَسَنَةِ وَجَادِلْهُمْ بِالَّتِي هِيَ أَحْسَنُ﴾ (النحل: 125)، فجمعت الآية بين الحكمة في اختيار الأسلوب، والرفق في الموعظة، وقوة الحجة في المجادلة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الصواعق المرسلة على الجهمية والمعطلة — ابن قيم الجوزية (في أصول الرد على الشبهات)', 1);
  END IF;

  -- 5) الفرق والمذاهب
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='151b1f2f-4c4a-479e-8873-0ca4b4b17f57' AND title='مدخل إلى الفرق الإسلامية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('مدخل إلى الفرق الإسلامية', 'تعريف عام موضوعي بنشأة الفرق الكلامية الكبرى وأصل الاختلاف بينها', '151b1f2f-4c4a-479e-8873-0ca4b4b17f57', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'نشأة الفرق ووصف عام', 'نشأت الفرق الكلامية في الإسلام تدريجياً بعد عصر الصحابة نتيجة خلافات سياسية (كالخوارج الذين خرجوا على علي رضي الله عنه، والشيعة الذين غلَوا في تقديم آل البيت) أو تأثر بمناهج فلسفية وافدة في مسائل القدر والصفات (كالمعتزلة والجهمية). لكل فرقة نشأة تاريخية وأصول اعتقادية تخصها تُدرَس دراسة علمية موضوعية لفهم أصل الخلاف، دون أن يعني ذلك حكماً عاماً قاطعاً على أفراد المنتسبين إليها.', 1),
    (v_lesson, 'evidence', 'موقف أهل السنة والجماعة', 'يتميز منهج أهل السنة والجماعة بالتمسك بما كان عليه النبي ﷺ وأصحابه من غير زيادة أو نقصان، كما ورد في الحديث الذي رواه الترمذي وحسَّنه: أن النبي ﷺ لما ذُكر له افتراق الأمة قال: «كلها في النار إلا واحدة» قالوا: من هي يا رسول الله؟ قال: «من كان على مثل ما أنا عليه اليوم وأصحابي». ودراسة الفرق عند أهل السنة غايتها بيان الحق ورد الشبهة، لا التعميم أو الطعن في الأشخاص.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الفرق بين الفرق — عبدالقاهر البغدادي (مرجع تاريخي في وصف نشأة الفرق)', 1);
  END IF;

  -- 6) الأديان المعاصرة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='dae2d656-9c92-4e36-b57e-49cc82ad5fc6' AND title='الإسلام والأديان الأخرى') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الإسلام والأديان الأخرى', 'موقف الإسلام العقدي من الأديان السماوية السابقة والأديان الوضعية المعاصرة', 'dae2d656-9c92-4e36-b57e-49cc82ad5fc6', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الأديان السماوية والوضعية', 'يؤمن المسلم بأن الله تعالى أرسل الرسل جميعاً بدين واحد في أصله هو توحيد الله، ثم طرأ التحريف والتبديل على الشرائع السابقة كاليهودية والنصرانية بعد رفع أنبيائها، فجاء الإسلام ديناً خاتماً ناسخاً لما قبله ومهيمناً عليه. أما الأديان الوضعية غير السماوية (كالبوذية والهندوسية وغيرها) فهي من صنع البشر لا وحي فيها، تُدرَس دراسة موضوعية معرفية دون خلط بينها وبين أديان أهل الكتاب.', 1),
    (v_lesson, 'evidence', 'دليل خاتمية الإسلام', 'قال تعالى: ﴿إِنَّ الدِّينَ عِنْدَ اللَّهِ الْإِسْلَامُ﴾ (آل عمران: 19)، وقال: ﴿وَمَنْ يَبْتَغِ غَيْرَ الْإِسْلَامِ دِينًا فَلَنْ يُقْبَلَ مِنْهُ وَهُوَ فِي الْآخِرَةِ مِنَ الْخَاسِرِينَ﴾ (آل عمران: 85). ومع هذا الاعتقاد الجازم، يأمر الإسلام بحسن معاملة غير المسلمين ممن لا يعادون المسلمين، والدعوة إليه بالحكمة لا بالإكراه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'مقارنة الأديان — د. أحمد شلبي (مرجع أكاديمي في التعريف بالأديان)', 1);
  END IF;

  -- 7) الإلحاد والشبهات الفكرية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='2ed3ded8-3c93-4844-a3d1-49b9868a15d7' AND title='دليل الفطرة على وجود الخالق') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('دليل الفطرة على وجود الخالق', 'الرد العقلي والفطري على شبهة الإلحاد وإنكار وجود الله', '2ed3ded8-3c93-4844-a3d1-49b9868a15d7', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الإلحاد وتعريفه', 'الإلحاد إنكار وجود الخالق سبحانه أو التوقف في إثباته، وهو مخالف لما فطر الله عليه الناس جميعاً من الإقرار الفطري بوجود خالق مدبِّر لهذا الكون، وإن انحرف بعض الناس عن مقتضى هذه الفطرة بتأثير بيئة أو شبهة عقلية أو هوى. والرد على الإلحاد يكون بإعادة المخالف إلى فطرته وعقله السليم وتفكُّره في آيات الله الكونية، لا بالإقصاء أو التسفيه.', 1),
    (v_lesson, 'evidence', 'الدليل الفطري والعقلي', 'قال تعالى: ﴿فَأَقِمْ وَجْهَكَ لِلدِّينِ حَنِيفًا فِطْرَتَ اللَّهِ الَّتِي فَطَرَ النَّاسَ عَلَيْهَا لَا تَبْدِيلَ لِخَلْقِ اللَّهِ﴾ (الروم: 30). وقرَّر القرآن دليلاً عقلياً بديهياً على وجوب وجود الخالق بقوله: ﴿أَمْ خُلِقُوا مِنْ غَيْرِ شَيْءٍ أَمْ هُمُ الْخَالِقُونَ * أَمْ خَلَقُوا السَّمَاوَاتِ وَالْأَرْضَ بَلْ لَا يُوقِنُونَ﴾ (الطور: 35-36)، فإذ استحال أن يخلقوا أنفسهم أو يكونوا هم الخالقين، تعيَّن أن لهم خالقاً هو الله وحده.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'وجود الله — د. عمر الأشقر (سلسلة العقيدة في ضوء الكتاب والسنة)', 1);
  END IF;

  -- 8) أثر الإيمان
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='ad2c13c0-9109-479a-bb4f-af0e284181b9' AND title='ثمرات الإيمان في حياة المسلم') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('ثمرات الإيمان في حياة المسلم', 'أثر الإيمان الصادق على طمأنينة القلب واستقامة السلوك والفوز بالآخرة', 'ad2c13c0-9109-479a-bb4f-af0e284181b9', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'أثره في الدنيا', 'للإيمان آثار عظيمة في حياة المؤمن الدنيوية قبل الأخروية: فهو يورث طمأنينة القلب وسكينته وعدم اضطرابه أمام تقلبات الحياة، ويدفع صاحبه إلى العمل الصالح والاستقامة على أمر الله، ويجعله يرى الابتلاء بعين الرضا والاحتساب لا الجزع والسخط.', 1),
    (v_lesson, 'evidence', 'دليله من القرآن', 'قال تعالى: ﴿أَلَا بِذِكْرِ اللَّهِ تَطْمَئِنُّ الْقُلُوبُ﴾ (الرعد: 28)، وقال في ثمرة الإيمان مقروناً بالعمل الصالح: ﴿مَنْ عَمِلَ صَالِحًا مِنْ ذَكَرٍ أَوْ أُنْثَى وَهُوَ مُؤْمِنٌ فَلَنُحْيِيَنَّهُ حَيَاةً طَيِّبَةً﴾ (النحل: 97)، فوعد الله المؤمن العامل بالصالحات بحياة طيبة في الدنيا قبل حسن الجزاء في الآخرة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'مدارج السالكين بين منازل إياك نعبد وإياك نستعين — ابن قيم الجوزية (في ثمرات الإيمان)', 1);
  END IF;

  -- 9) العقيدة الواسطية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='71bbb966-a9f4-4274-8a26-8493628ac731' AND title='التعريف برسالة العقيدة الواسطية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('التعريف برسالة العقيدة الواسطية', 'مؤلفها ومناسبة تأليفها ومحاورها الكبرى وأثرها في العلم الشرعي', '71bbb966-a9f4-4274-8a26-8493628ac731', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'التعريف بها ومؤلفها', 'العقيدة الواسطية رسالة مختصرة في اعتقاد أهل السنة والجماعة، ألَّفها شيخ الإسلام أحمد بن تيمية (ت 728هـ) إجابة لسؤال قاضٍ من مدينة واسط بالعراق طلب منه بياناً موجزاً لعقيدة أهل السنة، فسُميت بذلك "الواسطية"، وعنوانها الكامل "الرسالة الواسطية في اعتقاد الفرقة الناجية المنصورة".', 1),
    (v_lesson, 'body', 'محاورها الكبرى', 'تدور الرسالة حول محورين رئيسين: الأول توحيد الله في ربوبيته وألوهيته وأسمائه وصفاته على منهج إثبات بلا تمثيل وتنزيه بلا تعطيل، والثاني بيان منهج أهل السنة والجماعة في مسائل الإيمان والقدر والصحابة والإمامة وسائر مسائل الاعتقاد التي وقع فيها خلاف بين الفرق. وقد حظيت الرسالة بعناية علمية واسعة واعتُمدت متناً دراسياً لعقيدة أهل السنة في كثير من المعاهد والجامعات، وشُرحت بعشرات الشروح المعاصرة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'التعليقات على العقيدة الواسطية — الشيخ محمد بن صالح العثيمين', 1);
  END IF;

  -- 10) الأسماء والصفات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='59b3c424-54b1-412b-8b41-2ea0053d06a0' AND title='منهج أهل السنة في أسماء الله وصفاته') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('منهج أهل السنة في أسماء الله وصفاته', 'إثبات ما أثبته الله لنفسه من غير تمثيل، وتنزيهه عما نفاه عن نفسه من غير تعطيل', '59b3c424-54b1-412b-8b41-2ea0053d06a0', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'أصل المنهج', 'أصل مذهب أهل السنة والجماعة في هذا الباب أن يُؤمَن بما وصف الله به نفسه في كتابه وعلى لسان رسوله من الأسماء والصفات من غير تحريف لمعانيها ولا تعطيل لها عن حقيقتها، ومن غير تكييف لكيفيتها ولا تمثيل لها بصفات المخلوقين. فيُثبَت لله كل اسم وصفة وردت في الوحي كما جاءت، مع اعتقاد أنها على ما يليق بجلال الله لا تشابه صفات خلقه.', 1),
    (v_lesson, 'evidence', 'دليله من القرآن', 'الأصل في هذا الباب قوله تعالى: ﴿لَيْسَ كَمِثْلِهِ شَيْءٌ وَهُوَ السَّمِيعُ الْبَصِيرُ﴾ (الشورى: 11)، ففي هذه الآية نفي للمماثلة (تنزيه عن التمثيل) وإثبات للسمع والبصر (إثبات بلا تعطيل) في آية واحدة، وهذا هو الجامع الذي بنى عليه أهل السنة منهجهم في هذا الباب.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'العقيدة الواسطية — شيخ الإسلام ابن تيمية (فصل الأسماء والصفات)', 1);
  END IF;

  -- 11) النبوات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='86726108-43e9-4b03-932a-bc00010ea410' AND title='حقيقة النبوة وضرورتها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حقيقة النبوة وضرورتها', 'معنى النبوة وحكمة إرسال الرسل وصفاتهم الواجبة وختم النبوة بمحمد ﷺ', '86726108-43e9-4b03-932a-bc00010ea410', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'حكمة إرسال الرسل', 'النبوة اصطفاء إلهي لرجل من البشر يوحى إليه بشرع يبلغه للناس، واقتضت حكمة الله إرسال الرسل رحمة بالخلق حتى لا يبقى للناس عذر يوم القيامة بعدم بلوغ الحجة إليهم، ولإقامة الحجة عليهم بما يوافق فطرهم وعقولهم من توحيد الله وعبادته وحده. واتصف الرسل جميعاً بالصدق والأمانة وتبليغ ما أُمروا به كاملاً غير منقوص.', 1),
    (v_lesson, 'evidence', 'ختم النبوة ودليلها', 'قال تعالى في حكمة الإرسال: ﴿رُسُلًا مُبَشِّرِينَ وَمُنْذِرِينَ لِئَلَّا يَكُونَ لِلنَّاسِ عَلَى اللَّهِ حُجَّةٌ بَعْدَ الرُّسُلِ﴾ (النساء: 165)، وختم الله الرسالات بمحمد ﷺ فلا نبي بعده، قال تعالى: ﴿مَا كَانَ مُحَمَّدٌ أَبَا أَحَدٍ مِنْ رِجَالِكُمْ وَلَكِنْ رَسُولَ اللَّهِ وَخَاتَمَ النَّبِيِّينَ﴾ (الأحزاب: 40)، فوجب اعتقاد بطلان دعوى كل من ادَّعى النبوة بعده.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'النبوات — شيخ الإسلام ابن تيمية', 1);
  END IF;

  -- نشر التصنيفات الأحد عشر بعد اكتمال محتواها الأساسي
  UPDATE categories SET status='published', updated_at=now()
  WHERE slug IN (
    'sahaba-al-bayt','fitan-ashrat-saah','asma-ahkam','radd-shubuhat-aqeedah',
    'firaq-madhahib','adyan-muasira','ilhad-shubuhat-fikriyya','athar-iman',
    'aqeedah-wasitiyya','asma-wa-sifat','nubuwat'
  ) AND status='draft';
END $$;
